"use client"; import { useState } from "react"; import { useRouter } from "next/navigation"; import PageHeader from "@/components/PageHeader"; import { authApi, saveSession } from "@/lib/api"; export default function RegisterPage() { const router = useRouter(); const [form, setForm] = useState({ fullName: "", email: "", phone: "", password: "", confirmPassword: "", role: "", address: "", country: "Nepal", city: "", businessName: "", businessType: "", licenseNumber: "", operatingHours: "", preferredContact: "phone", termsAccepted: false }); const [error, setError] = useState(""); const [loading, setLoading] = useState(false); const handle = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => { const { name, value, type } = e.target; const checked = type === "checkbox" ? (e.target as HTMLInputElement).checked : undefined; setForm((f:any) => ({ ...f, [name]: type === "checkbox" ? checked : value })); }; const submit = async () => { setError(""); if (!form.fullName || !form.email || !form.password || !form.role) return setError("Please fill all required fields."); setLoading(true); try { const data = await authApi.register(form); saveSession(data.token, data.user); router.push("/dashboard"); } catch (err:any) { setError(err.message || "Registration failed"); } finally { setLoading(false); } }; const seller = form.role === "farmer" || form.role === "restaurant" || form.role === "industrial"; return <><PageHeader title="Create account" text="Register according to the requirement document with full role-based details." /><section className="section"><div className="container"><div className="card card-pad">{error && <div className="notice notice-error">{error}</div>}<div className="form-grid"><input className="input" name="fullName" placeholder="Full name" value={form.fullName} onChange={handle} /><input className="input" name="email" placeholder="Email" value={form.email} onChange={handle} /><input className="input" name="phone" placeholder="Phone" value={form.phone} onChange={handle} /><select className="select" name="role" value={form.role} onChange={handle}><option value="">Select role</option><option value="farmer">Farmer</option><option value="restaurant">Restaurant</option><option value="industrial">Industrial user</option><option value="customer">Customer</option></select><input className="input" type="password" name="password" placeholder="Password" value={form.password} onChange={handle} /><input className="input" type="password" name="confirmPassword" placeholder="Confirm password" value={form.confirmPassword} onChange={handle} /><input className="input" name="address" placeholder="Address" value={form.address} onChange={handle} /><input className="input" name="city" placeholder="City" value={form.city} onChange={handle} /><input className="input" name="country" placeholder="Country" value={form.country} onChange={handle} /><select className="select" name="preferredContact" value={form.preferredContact} onChange={handle}><option value="phone">Preferred contact: phone</option><option value="email">Preferred contact: email</option></select>{seller && <input className="input" name="businessName" placeholder="Business name" value={form.businessName} onChange={handle} />}{seller && <input className="input" name="businessType" placeholder="Business type" value={form.businessType} onChange={handle} />}{seller && <input className="input" name="licenseNumber" placeholder="License number" value={form.licenseNumber} onChange={handle} />}{seller && <input className="input" name="operatingHours" placeholder="Operating hours" value={form.operatingHours} onChange={handle} />}</div><label style={{ display: "flex", gap: 10, marginTop: 16 }}><input type="checkbox" name="termsAccepted" checked={form.termsAccepted} onChange={handle} /><span>I accept the terms and privacy policy.</span></label><div style={{ marginTop: 16 }}><button className="btn btn-primary" onClick={submit} disabled={loading}>{loading ? "Creating account..." : "Create account"}</button></div></div></div></section></>; }
